mapper.select:
SELECT id, policy_no, company, fee, insured_time, start_time, end_time, applicant, insured_person, contact, vehicle_id, insurance_type, status, remark, create_time, update_time FROM vehicle_insurance
AND id = #{id}
AND vehicle_id = #{vehicleId}
AND policy_no LIKE CONCAT('%', #{policyNo}, '%')
AND company LIKE CONCAT('%', #{company}, '%')
AND status = #{status}
ORDER BY create_time DESC

